+std::vector<double> RobotStateRT::unpackVector(uint8_t * buf, int start_index,
+		int nr_of_vals) {
+	uint64_t q;
+	std::vector<double> ret;
+	for (int i = 0; i < nr_of_vals; i++) {
+		memcpy(&q, &buf[start_index + i * sizeof(q)], sizeof(q));
+		ret.push_back(ntohd(q));
+	}
+	return ret;
+}
