+std::vector<bool> RobotStateRT::unpackDigitalInputBits(int64_t data) {
+	std::vector<bool> ret;
+	for (int i = 0; i < 64; i++) {
+		ret.push_back((data & (1 << i)) >> i);
+	}
+	return ret;
+}
